function activate(context) {
  var en = context.locale === 'en-US';
  context.ui.addToolbarButton({
    icon: 'sparkles',
    label: 'Hello',
    onClick: function () {
      context.ui.showNotification(
        en ? 'Plugin sandbox is working' : '插件沙箱运行正常',
        'success'
      );
    },
  });
}
